// frontend/src/components/shared/DiceFaces.jsx
//
// Polyhedral die-face icons (d4..d100) on a 1024x1024 grid, FILLED with
// currentColor so each die takes the surrounding text color. Use DIE_ICONS[key].
import React from 'react';

function DieFace({ size = 28, viewBox = '0 0 1024 1024', style, children, ...props }) {
  // Sized by HEIGHT with width:auto, so each die takes its own aspect ratio:
  // square dice (1024x1024) render square, while the wider d100 (1280x1024)
  // renders proportionally wider instead of being squeezed into a square box.
  return (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox={viewBox}
      fill="currentColor" fillRule="evenodd" clipRule="evenodd" aria-hidden="true"
      style={{ height: size, width: 'auto', display: 'block', ...style }} {...props}>
      {children}
    </svg>
  );
}

